parameters.functionCode:
// =============================================
// Prepare recruit data and generate access token
// =============================================
const data = $input.first().json;

// Split full_name into firstName / lastName for GHL contacts API
const nameParts = (data.full_name || '').trim().split(/\s+/);
const firstName = nameParts[0] || '';
const lastName = nameParts.slice(1).join(' ') || '';

// Generate a unique 32-character access token
const chars = 'abcdefghijklmnopqrstuvwxyz0123456789';
let token = '';
for (let i = 0; i < 32; i++) {
  token += chars[Math.floor(Math.random() * chars.length)];
}

return [{
  json: {
    ...data,
    firstName,
    lastName,
    token
  }
}];

// =============================================
// Get recruit data from upstream nodes
// =============================================
const webhookData = $('Webhook: Recruit Created').first().json;
const contactId = $('Create Contact in GHL').first().json.contact.id;
const startDate = new Date(webhookData.start_date);

// ============================================
// TRAINING STEPS (8 steps - same for US and Canada)
// Source: WFG Onboarding Process Validation PDF
// Note: Training descriptions are placeholders in the PDF
//       pending official content from Jorge and Liz.
//       Titles confirmed accurate from Miro board.
// ============================================
const trainingSteps = [
  {
    id: 't1',
    title: 'Meet Spouse/Influential Person',
    days: 1,
    description: 'Meet the spouse or influential person in the recruit\'s life.',
    instructions: [
      'Schedule a 60-90 minute meeting with your assigned trainer',
      'Prepare questions about the business opportunity',
      'Discuss your personal financial goals',
      'Set clear 30/60/90 day objectives'
    ],
    resources: 'Your trainer — meeting agenda template available from your upline',
    timeline: '24\u201348 hours'
  },
  {
    id: 't2',
    title: 'Get Your Startup Kit',
    days: 3,
    description: 'Receive and review all materials in your new agent startup package.',
    instructions: [
      'Obtain your physical or digital startup kit from your trainer',
      'Review all included training materials',
      'Set up your business cards and marketing materials',
      'Organize your client presentation tools'
    ],
    resources: 'Startup kit contents checklist in your trainer guidebook',
    timeline: '1 day'
  },
  {
    id: 't3',
    title: 'Start Your Licensing Path',
    days: 15,
    description: 'Begin working through the Licensing pathway steps concurrently.',
    instructions: [
      'Switch to the Licensing tab in the onboarding planner',
      'Begin with Step 1: Sign Your Membership Agreement',
      'Work through licensing steps while continuing training',
      'Keep your trainer updated on licensing progress'
    ],
    resources: 'See Licensing pathway in the onboarding planner for detailed steps',
    timeline: '30 days'
  },
  {
    id: 't4',
    title: 'Complete Your PFS',
    days: 21,
    description: 'Finish your Personal Financial Strategy session and documentation.',
    instructions: [
      'Schedule your PFS session with your trainer',
      'Gather your personal financial documents',
      'Complete the full PFS analysis process',
      'Review your own financial plan and protection gaps'
    ],
    resources: 'PFS workbook and forms in your startup kit',
    timeline: '24\u201348 hours'
  },
  {
    id: 't5',
    title: 'Attend All Workshops and BPM',
    days: 31,
    description: 'Participate in all required workshops and Business Presentation Meetings.',
    instructions: [
      'Get the workshop and BPM schedule from your trainer',
      'Attend all Saturday training workshops',
      'Attend weekly BPM meetings consistently',
      'Take notes and participate actively in all sessions'
    ],
    resources: 'Workshop calendar available in team communications',
    timeline: 'Ongoing — attend all scheduled events for first 90 days'
  },
  {
    id: 't6',
    title: 'Complete Trainer Guidebook & Share List',
    days: 36,
    description: 'Study the trainer guidebook and build your initial prospect list.',
    instructions: [
      'Read the entire trainer guidebook cover to cover',
      'Complete all exercises in the guidebook',
      'Build your share list of at least 100 names',
      'Categorize contacts by relationship and priority'
    ],
    resources: 'Share list template in your startup kit',
    timeline: '30 days'
  },
  {
    id: 't7',
    title: 'Complete Your Field Training',
    days: 45,
    description: 'Shadow experienced agents and complete hands-on client appointments.',
    instructions: [
      'Schedule field training sessions with your trainer',
      'Observe at least 5 client appointments',
      'Conduct 3 supervised appointments yourself',
      'Debrief with your trainer after each session'
    ],
    resources: 'Field training log sheet from your trainer',
    timeline: '30 days'
  },
  {
    id: 't8',
    title: 'Complete Your GX 315',
    days: 60,
    description: 'Finish the GX 315 advanced training certification program.',
    instructions: [
      'Register for the GX 315 program through WFG University',
      'Complete all online modules and assessments',
      'Attend any required live training sessions',
      'Pass the final certification exam'
    ],
    resources: 'GX 315 access through WFG University portal',
    timeline: '30 days'
  }
];

const formattedSteps = trainingSteps.map((step, index) => {
  const deadline = new Date(startDate);
  deadline.setDate(deadline.getDate() + step.days);

  return {
    recruit_id: contactId,
    step_id: step.id,
    step_number: index + 1,
    step_title: step.title,
    step_description: step.description,
    instructions: JSON.stringify(step.instructions),
    resources: step.resources,
    timeline_guidance: step.timeline,
    deadline_date: deadline.toISOString().split('T')[0],
    days_from_start: step.days,
    is_completed: false,
    status: 'On Track'
  };
});

return formattedSteps.map(step => ({ json: step }));

